import argparse
from kafka import KafkaAdminClient
from kafka.admin import NewTopic

def create_topic(admin_client, topic_name, num_partitions, replication_factor, config):
    topic = NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor, 
                     config=config)
    admin_client.create_topics([topic])
    print(f"Topic '{topic_name}' created with {num_partitions} partitions and replication factor {replication_factor}.")

def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration')
    parser.add_argument('topic_name', type=str, help='Name of the topic to create')
    parser.add_argument('--partitions', type=int, default=1, help='Number of partitions')
    parser.add_argument('--replication', type=int, default=1, help='Replication factor')
    parser.add_argument('--config', type=str, action='append', help='Configuration in key=value format')

    args = parser.parse_args()

    # Parse configurations into a dictionary
    config = {}
    if args.config:
        for item in args.config:
            key, value = item.split('=')
            config[key] = value

    admin_client = KafkaAdminClient(bootstrap_servers='localhost:9092')

    create_topic(admin_client, args.topic_name, args.partitions, args.replication, config)

    admin_client.close()

if __name__ == "__main__":
    main()